_WINDOWS_PRIORITY_CLASSES = {
    "low": 0x00000040,  # IDLE_PRIORITY_CLASS
    "below_normal": 0x00004000,  # BELOW_NORMAL_PRIORITY_CLASS
    "normal": 0x00000020,  # NORMAL_PRIORITY_CLASS
    "above_normal": 0x00008000,  # ABOVE_NORMAL_PRIORITY_CLASS
    "high": 0x00000080,  # HIGH_PRIORITY_CLASS
}

_POSIX_NICE_VALUES = {
    "low": 10,
    "below_normal": 5,
    "normal": 0,
    "above_normal": -5,
    "high": -10,
}


class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: cabc.Mapping[str, str] | None = None,
        require_save: bool = True,
        extension: str = ".txt",
        process_priority: str | None = None,
        escape_shell: bool = False,
    ) -> None:
        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension
        self.process_priority = process_priority
        self.escape_shell = escape_shell

    def _get_priority_popen_kwargs(self) -> dict[str, t.Any]:
        """Build the ``subprocess.Popen`` kwargs needed to apply
        ``self.process_priority`` to the editor process, if possible.
        Returns an empty dict if no priority should be applied or the
        requested priority isn't recognized.
        """
        if self.process_priority is None:
            return {}

        if WIN:
            priority_class = _WINDOWS_PRIORITY_CLASSES.get(self.process_priority)

            if priority_class is None:
                return {}

            return {"creationflags": priority_class}

        nice_value = _POSIX_NICE_VALUES.get(self.process_priority)

        if nice_value is None:
            return {}

        def _apply_nice_value() -> None:
            try:
                os.nice(nice_value)
            except OSError:
                pass

        return {"preexec_fn": _apply_nice_value}

