def edit_file(self, filename: str) -> None:
    import subprocess

    editor = self.get_editor()
    environ: dict[str, str] | None = None

    if self.env:
        environ = os.environ.copy()
        environ.update(self.env)

    if self.escape_shell:
        import shlex

        quoted_editor = " ".join(shlex.quote(part) for part in shlex.split(editor))
        command = f"{quoted_editor} {shlex.quote(filename)}"
    else:
        command = f'{editor} "{filename}"'

    popen_kwargs = self._get_priority_popen_kwargs()

    try:
        try:
            c = subprocess.Popen(command, env=environ, shell=True, **popen_kwargs)
        except OSError:
            # The requested process priority could not be applied.
            # Fall back to launching the editor normally rather than
            # failing the whole edit operation.
            if not popen_kwargs:
                raise
            c = subprocess.Popen(command, env=environ, shell=True)

        exit_code = c.wait()
        if exit_code != 0:
            raise ClickException(
                _("{editor}: Editing failed").format(editor=editor)
            )
    except OSError as e:
        raise ClickException(
            _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
        ) from e

